# ── axes3d sub-module (for `from mpl_toolkits.mplot3d.axes3d import Axes3D`) ──
def _get_test_data(delta=0.05):
    """Sample :math:`x \\cdot e^{-(x^2 + y^2)}` over a small grid — the
    standard sample dataset used in matplotlib's 3-D demos."""
    import numpy as np
    x = y = np.arange(-3.0, 3.0, delta)
    X, Y = np.meshgrid(x, y)
    Z = X * np.exp(-X * X - Y * Y)
    return X, Y, Z


class _Axes3DModule:
    Axes3D = Axes3D
    Axes = Axes3D
    get_test_data = staticmethod(_get_test_data)
    def __getattr__(self, name):
        return Axes3D

axes3d = _Axes3DModule()


