projection = _ProjectionModule()


# Register sub-modules in sys.modules so `import mpl_toolkits.mplot3d.axes3d` works
_this = _sys.modules[__name__]
_sys.modules['mpl_toolkits.mplot3d.art3d'] = art3d
_sys.modules['mpl_toolkits.mplot3d.proj3d'] = proj3d
_sys.modules['mpl_toolkits.mplot3d.axis3d'] = axis3d
_sys.modules['mpl_toolkits.mplot3d.axes3d'] = axes3d
_sys.modules['mpl_toolkits.mplot3d.projection'] = projection


# ─── Public-name re-exports for the 3D classes ───────────────────────
#
# Code reaches in via the documented names ``Poly3DCollection``,
# ``Line3D``, ``Patch3D``, etc. — no leading underscore. The stubs
# above already exist under the underscore names; expose both forms.

Poly3DCollection      = _Poly3DCollection
Line3DCollection      = _Line3DCollection
Collection3D          = _Collection3D
Line3D                = _Line3D
Patch3D               = _Patch3D
Patch3DCollection     = _Patch3DCollection
Path3DCollection      = _Path3DCollection
PathPatch3D           = _PathPatch3D
Text3D                = _Text3D


# ── 2D base classes that upstream mplot3d re-exports ────────────
try:
    from matplotlib.collections import (
        Collection as Collection,
        LineCollection as LineCollection,
        PolyCollection as PolyCollection,
        PathCollection as PathCollection,
        PatchCollection as PatchCollection,
    )
except Exception:
    class Collection: pass
    class LineCollection(Collection): pass
    class PolyCollection(Collection): pass
    class PathCollection(Collection): pass
    class PatchCollection(Collection): pass

try:
    from matplotlib.patches import Patch as Patch
except Exception:
    class Patch: pass

try:
    from matplotlib.colors import Normalize as Normalize
except Exception:
    class Normalize:
        def __init__(self, vmin=None, vmax=None, clip=False): pass

try:
    from matplotlib.transforms import Bbox as Bbox
except Exception:
    class Bbox:
        x0 = y0 = 0.0; x1 = y1 = 1.0

try:
    from matplotlib.tri import Triangulation as Triangulation
except Exception:
    class Triangulation:
        def __init__(self, x, y, triangles=None, mask=None): pass


# ── Module-level helper functions upstream exposes ──────────────
def get_test_data(delta=0.05):
    return _get_test_data(delta)

def collection_2d_to_3d(col, zs=0, zdir='z'):       return col
def line_2d_to_3d(line, zs=0, zdir='z'):            return line
def line_collection_2d_to_3d(col, zs=0, zdir='z'):  return col
def patch_2d_to_3d(patch, z=0, zdir='z'):           return patch
def patch_collection_2d_to_3d(col, zs=0, zdir='z'): return col
def pathpatch_2d_to_3d(pathpatch, z=0, zdir='z'):   return pathpatch
def poly_collection_2d_to_3d(col, zs=0, zdir='z'):  return col
def text_2d_to_3d(text, z=0, zdir='z'):             return text
def get_dir_vector(zdir):                           return (0, 0, 1)
def juggle_axes(xs, ys, zs, zdir):                  return xs, ys, zs
def rotate_axes(xs, ys, zs, zdir):                  return xs, ys, zs

# Stdlib symbols upstream re-exports
from collections import defaultdict  # noqa: E402,F401
from contextlib import contextmanager  # noqa: E402,F401

# proj3d helpers — surfaced at the package level for ``from
# mpl_toolkits.mplot3d import proj_transform`` style imports.
def proj_transform(xs, ys, zs, M):
    return xs, ys, zs
def proj_transform_clip(xs, ys, zs, M, focal_length=None):
    return xs, ys, zs, [True] * (len(xs) if hasattr(xs, '__len__') else 1)
def inv_transform(*a, **kw):       return None
def world_transformation(*a, **kw):  return None
